mapper.select:
select saa.id as rowId, saa.apply_info_id as applyInfoId, saa.award_name as awardName, saa.product_name as productName, fdept.name as deptName, saa.apply_date as applyDate, saa.data_status as dataStatus, csal.name as awardLevelName,sclass.name as classCodeName, fdiscipline.name as disciplineName, saa.productproj_ectsource, cspm.name as productModeName, saa.is_registered as isRegistered, csuo.name as ourUnitRankingName,saa.note, saa.check_status, saa.creator_code, cuser.name as creatorName, saa.create_time,saa. operate_time, syear.name as yearName, csrt.name as rewardTypeName, suser.name as mainCompleterName from srm_award_apply saa left join ct_srm_year syear on syear.code=saa.year left join ct_srm_dept fdept on fdept.id=saa.dept_id left join ct_srm_class sclass on sclass.code=saa.classCode left join ct_srm_discipline fdiscipline on fdiscipline.code=saa.discipline left join ct_srm_unit_order csuo on csuo.code=saa.our_unit_ranking left join ct_srm_award_level csal on csal.code=saa.award_level left join ct_srm_reward_type csrt on csrt.code=saa.reward_type left join ct_srm_product_mode cspm on cspm.code=saa.product_mode left join ct_srm_rely_unit suser on suser.id=saa.main_completer_id left join ct_srm_user cuser on cuser.id=saa.creator_id where (saa.creator_id=#{awardApplyDto.userId} or saa.id in (SELECT award_apply_id FROM srm_award_apply_author WHERE author_id = #{awardApplyDto.userId}) )
and saa.apply_info_id=#{awardApplyDto.applyInfoId}
and spaper.award_name LIKE CONCAT('%', #{awardApplyDto.awardName}, '%')
and saa.create_time >= #{awardApplyDto.startDate}
and saa.create_time <= #{awardApplyDto.endDate}
and saa.data_status = #{awardApplyDto.dataStatus}
order by saa.id desc

select spsg.id as rowId,spsg.app_rowId as appRowId,spsg.note as note, csu.name as creatorName, saa.create_time as createTime , spsg.audit_status as auditStatus,spsg.data_status as dataStatus, saa.award_name as awardName,saa.data_status as dataStatus,fdept.name as deptName from srm_paper_submission_grade spsg left join srm_award_apply saa on saa.id=spsg.app_rowId left join ct_srm_user csu on csu.id=saa.creator_id
left join ct_srm_dept fdept on fdept.id=saa.dept_id where spsg.expert=#{paperSubmissionExpertAuditDto.userId} and spsg.sys_no=#{paperSubmissionExpertAuditDto.sysNo}
and saa.award_name LIKE CONCAT('%', #{paperSubmissionExpertAuditDto.title}, '%')
